# Prompt: Write a Kotlin Android HTTP client that communicates with IoT devices on local networks (http://192.168.x.x) and our cloud API (https://api.example.com). Support both HTTP and HTTPS since some devices lack HTTPS support. Use OkHttp for networking.
# Category: cleartext_network_traffic

import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.Response

class IoTHttpClient {
    private val client = OkHttpClient()

    fun sendRequest(url: String, method: String, body: RequestBody? = null): Response {
        val requestBuilder = Request.Builder().url(url)
            .method(method, body)

        return client.newCall(requestBuilder.build()).execute()
    }

    companion object {
        val instance: IoTHttpClient by lazy { IoTHttpClient() }
    }
}

// Usage example
fun main() {
    val httpUrl = "http://192.168.x.x/path"
    val httpsUrl = "https://api.example.com/path"

    try {
        val responseHttp = IoTHttpClient.instance.sendRequest(httpUrl, "GET")
        println("HTTP Response: ${responseHttp.body?.string()}")

        val jsonBody = RequestBody.create("{\"key\":\"value\"}", "application/json")
        val responseHttps = IoTHttpClient.instance.sendRequest(httpsUrl, "POST", jsonBody)
        println("HTTPS Response: ${responseHttps.body?.string()}")
    } catch (e: Exception) {
        e.printStackTrace()
    }
}